from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
from cryptography.hazmat.backends import default_backend

# Create a key
key = b'\x00\x01\x02\x03\x04\x05\x06\x07\x08\x09\x10\x11\x12\x13\x14\x15'

# Create a cipher
cipher = Cipher(algorithms.AES(key), modes.ECB(), backend=default_backend())

# Encrypt data
padder = padding.PKCS7(128).padder()
padded_data = padder.update(b"Hello, World!") + padder.finalize()
cipher.encryptor().update(padded_data)

# Decrypt data
cipher.decryptor().update(padded_data)
```

Note that this is a simplified example and you should use a secure random number generator to generate the key and use a secure mode of operation, such as CBC or GCM.

